import { app, BrowserWindow, ipcMain } from 'electron';
import { mkdir, readFile, writeFile } from 'node:fs/promises';
import path from 'node:path';
import type { PersistedTreeState, UserSettings } from './shared/types';
// This allows TypeScript to pick up the magic constants that's auto-generated by Forge's Webpack
// plugin that tells the Electron app where to look for the Webpack-bundled app code (depending on
// whether you're running in development or production).
declare const MAIN_WINDOW_WEBPACK_ENTRY: string;
declare const MAIN_WINDOW_PRELOAD_WEBPACK_ENTRY: string;

// Handle creating/removing shortcuts on Windows when installing/uninstalling.
if (require('electron-squirrel-startup')) {
  app.quit();
}

const getTreeStatePath = (): string =>
  path.join(app.getPath('userData'), 'data', 'tree-state.json');
const getUserSettingsPath = (): string =>
  path.join(app.getPath('userData'), 'data', 'user-settings.json');

const loadTreeState = async (): Promise<PersistedTreeState | null> => {
  try {
    const filePath = getTreeStatePath();
    const contents = await readFile(filePath, 'utf-8');
    return JSON.parse(contents) as PersistedTreeState;
  } catch (error: unknown) {
    if (
      typeof error === 'object' &&
      error !== null &&
      'code' in error &&
      (error as { code?: string }).code === 'ENOENT'
    ) {
      return null;
    }

    throw error;
  }
};

const saveTreeState = async (state: PersistedTreeState): Promise<void> => {
  const filePath = getTreeStatePath();
  const folderPath = path.dirname(filePath);
  await mkdir(folderPath, { recursive: true });
  await writeFile(filePath, JSON.stringify(state, null, 2), 'utf-8');
};

const loadUserSettings = async (): Promise<UserSettings | null> => {
  try {
    const filePath = getUserSettingsPath();
    const contents = await readFile(filePath, 'utf-8');
    return JSON.parse(contents) as UserSettings;
  } catch (error: unknown) {
    if (
      typeof error === 'object' &&
      error !== null &&
      'code' in error &&
      (error as { code?: string }).code === 'ENOENT'
    ) {
      return null;
    }

    throw error;
  }
};

const saveUserSettings = async (settings: UserSettings): Promise<void> => {
  const filePath = getUserSettingsPath();
  const folderPath = path.dirname(filePath);
  await mkdir(folderPath, { recursive: true });
  await writeFile(filePath, JSON.stringify(settings, null, 2), 'utf-8');
};

ipcMain.handle('tree:load', async () => loadTreeState());
ipcMain.handle('tree:save', async (_event, state: PersistedTreeState) => {
  await saveTreeState(state);
});
ipcMain.handle('settings:load', async () => loadUserSettings());
ipcMain.handle('settings:save', async (_event, settings: UserSettings) => {
  await saveUserSettings(settings);
});

const createWindow = (): void => {
  // Create the browser window.
  const mainWindow = new BrowserWindow({
    height: 600,
    width: 800,
    webPreferences: {
      preload: MAIN_WINDOW_PRELOAD_WEBPACK_ENTRY,
    },
  });

  // and load the index.html of the app.
  mainWindow.loadURL(MAIN_WINDOW_WEBPACK_ENTRY);

  // Open the DevTools.
  mainWindow.webContents.openDevTools();
};

// This method will be called when Electron has finished
// initialization and is ready to create browser windows.
// Some APIs can only be used after this event occurs.
app.on('ready', createWindow);

// Quit when all windows are closed, except on macOS. There, it's common
// for applications and their menu bar to stay active until the user quits
// explicitly with Cmd + Q.
app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') {
    app.quit();
  }
});

app.on('activate', () => {
  // On OS X it's common to re-create a window in the app when the
  // dock icon is clicked and there are no other windows open.
  if (BrowserWindow.getAllWindows().length === 0) {
    createWindow();
  }
});

